using System;
using System.Collections.Generic;
using System.Xml;

public class XmlConfigurationParser
{
    public Dictionary<string, string> ParseConfigurationWithXmlDocument(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        
        var xmlDoc = new XmlDocument();
        xmlDoc.Load(xmlFilePath);
        
        XmlNodeList settingNodes = xmlDoc.SelectNodes("//setting");
        
        if (settingNodes != null)
        {
            foreach (XmlNode node in settingNodes)
            {
                string key = node.Attributes?["key"]?.Value;
                string value = node.Attributes?["value"]?.Value ?? node.InnerText;
                
                if (!string.IsNullOrEmpty(key))
                {
                    settings[key] = value;
                }
            }
        }
        
        return settings;
    }
    
    public Dictionary<string, string> ParseConfigurationWithXmlReader(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        
        var readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD,
            XmlResolver = new XmlUrlResolver()
        };
        
        using (XmlReader reader = XmlReader.Create(xmlFilePath, readerSettings))
        {
            string currentKey = null;
            
            while (reader.Read())
            {
                if (reader.NodeType == XmlNodeType.Element && reader.Name == "setting")
                {
                    currentKey = reader.GetAttribute("key");
                    string value = reader.GetAttribute("value");
                    
                    if (!string.IsNullOrEmpty(currentKey))
                    {
                        if (!string.IsNullOrEmpty(value))
                        {
                            settings[currentKey] = value;
                        }
                        else if (reader.Read() && reader.NodeType == XmlNodeType.Text)
                        {
                            settings[currentKey] = reader.Value;
                        }
                    }
                }
            }
        }
        
        return settings;
    }
    
    public Dictionary<string, string> ParseHierarchicalConfiguration(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        
        var xmlDoc = new XmlDocument();
        xmlDoc.Load(xmlFilePath);
        
        ProcessNode(xmlDoc.DocumentElement, "", settings);
        
        return settings;
    }
    
    private void ProcessNode(XmlNode node, string prefix, Dictionary<string, string> settings)
    {
        if (node == null) return;
        
        string currentPrefix = string.IsNullOrEmpty(prefix) ? node.Name : prefix + "." + node.Name;
        
        if (node.Attributes != null)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                settings[currentPrefix + "." + attr.Name] = attr.Value;
            }
        }
        
        if (node.HasChildNodes && node.ChildNodes.Count == 1 && node.FirstChild.NodeType == XmlNodeType.Text)
        {
            settings[currentPrefix] = node.InnerText;
        }
        else if (node.HasChildNodes)
        {
            foreach (XmlNode childNode in node.ChildNodes)
            {
                if (childNode.NodeType == XmlNodeType.Element)
                {
                    ProcessNode(childNode, currentPrefix, settings);
                }
            }
        }
    }
}